316.             >= 31 => $"{(int)(absDiff.TotalDays / 30)} months",
317.             >= 1 => $"{(int)absDiff.TotalDays} days",
318.             _ => absDiff.TotalHours switch
319.             {
320.                 >= 1 => $"{(int)absDiff.TotalHours} hours",
321.                 _ => absDiff.TotalMinutes switch
322.                 {
323.                     >= 1 => $"{(int)absDiff.TotalMinutes} minutes",
